1. use anyhow::Result;
2. use clap::{Parser, Subcommand};
3. 
4. /// Engram workspace-local MCP plugin.
5. ///
6. /// Manages per-workspace daemon processes that serve MCP tool calls via stdio.
7. /// The shim subcommand (default) is the MCP client entry point; the daemon
8. /// subcommand is spawned automatically by the shim.
9. #[derive(Debug, Parser)]
10. #[command(name = "engram", version, about)]
11. struct Cli {
12.     #[command(subcommand)]
13.     command: Option<Command>,
14. }
15. 
16. #[derive(Debug, Subcommand)]
17. enum Command {
18.     /// Run as MCP stdio shim (default). Connects to or spawns the workspace daemon,
19.     /// then proxies MCP JSON-RPC from stdin to the daemon and back to stdout.
20.     Shim,
21.     /// Run as workspace daemon. Manages workspace state, IPC server, file watching,
22.     /// and idle timeout. Spawned automatically by the shim; not intended for direct use.
23.     Daemon {
24.         /// Absolute path to the workspace root.
25.         #[arg(long)]
26.         workspace: String,
27.     },
28.     /// Install the engram plugin into the current workspace.
29.     /// Creates `.engram/` directory structure, generates MCP configuration,
30.     /// and writes agent hook files for GitHub Copilot, Claude Code, and Cursor.
31.     Install {
32.         /// Generate only agent hook files; skip `.engram/` data file creation.
33.         #[arg(long)]
34.         hooks_only: bool,
35.         /// Skip agent hook file generation.
36.         #[arg(long)]
37.         no_hooks: bool,
38.         /// MCP HTTP endpoint port to embed in hook file URLs.
39.         #[arg(long, default_value_t = engram::installer::DEFAULT_PORT)]
40.         port: u16,
41.     },
42.     /// Update the engram plugin runtime artifacts (binary references, config templates).
43.     /// Preserves existing workspace data files.
44.     Update,
45.     /// Reinstall the engram plugin, cleaning runtime artifacts while preserving data.
46.     Reinstall,
47.     /// Remove the engram plugin from the workspace.
48.     /// Stops any running daemon and removes plugin artifacts.
49.     Uninstall {
50.         /// Keep workspace data files (tasks.md, config.toml, etc.) after uninstall.
51.         #[arg(long)]
52.         keep_data: bool,
53.     },
54. }
55. 
56. #[tokio::main]
57. async fn main() -> Result<()> {
58.     let cli = Cli::parse();
59. 
60.     match cli.command.unwrap_or(Command::Shim) {
61.         Command::Shim => {
62.             engram::shim::run().await?;
63.         }
64.         Command::Daemon { workspace } => {
65.             engram::daemon::run(&workspace).await?;
66.         }
67.         Command::Install {
68.             hooks_only,
69.             no_hooks,
70.             port,
71.         } => {
72.             let workspace = std::env::current_dir()?;
73.             let opts = engram::installer::InstallOptions {
74.                 hooks_only,
75.                 no_hooks,
76.                 port,
77.             };
78.             engram::installer::install(&workspace, &opts).await?;
79.         }
80.         Command::Update => {
81.             let workspace = std::env::current_dir()?;
82.             engram::installer::update(&workspace).await?;
83.         }
84.         Command::Reinstall => {
85.             let workspace = std::env::current_dir()?;
86.             engram::installer::reinstall(&workspace).await?;
87.         }
88.         Command::Uninstall { keep_data } => {
89.             let workspace = std::env::current_dir()?;
90.             engram::installer::uninstall(&workspace, keep_data).await?;
91.         }
92.     }
93. 
94.     Ok(())
95. }
96.

