1. //! Shim lifecycle: daemon health-check, spawn, and wait-for-ready logic.
2. //!
3. //! Before forwarding the first request the shim checks whether a daemon is
4. //! already running by sending an `_health` IPC message. If the check fails
5. //! (no daemon running), the shim spawns a new daemon process via
6. //! `tokio::process::Command` and waits with exponential backoff until the
7. //! daemon reports `Ready`.
8. 
9. use std::path::Path;
10. use std::time::Duration;
11. 
12. use serde_json::Value;
13. use tracing::{debug, info, instrument};
14. 
15. use crate::daemon::ipc_server::ipc_endpoint;
16. use crate::daemon::protocol::IpcRequest;
17. use crate::errors::{DaemonError, EngramError};
18. 
19. // ── Backoff constants ─────────────────────────────────────────────────────────
20. 
21. /// Maximum number of health-check poll attempts after spawning the daemon.
22. const MAX_BACKOFF_ATTEMPTS: u32 = 30;
23. /// Initial delay before the first poll (milliseconds).
24. const INITIAL_BACKOFF_MS: u64 = 10;
25. /// Maximum delay cap per backoff step (milliseconds).
26. const MAX_BACKOFF_MS: u64 = 500;
27. /// Default total wall-clock budget allowed for the ready-wait loop (milliseconds).
28. const DEFAULT_READY_TIMEOUT_MS: u64 = 30_000;
29. 
30. /// Parse a ready-timeout value from an optional raw string.
31. ///
32. /// Returns the parsed `u64` milliseconds if `raw` is `Some` and parses
33. /// successfully, otherwise falls back to [`DEFAULT_READY_TIMEOUT_MS`].
34. fn parse_timeout_ms(raw: Option<&str>) -> u64 {
35.     raw.and_then(|s| s.parse::<u64>().ok())
36.         .unwrap_or(DEFAULT_READY_TIMEOUT_MS)
37. }
38. 
39. /// Return the ready-wait timeout in milliseconds.
40. ///
41. /// Reads `ENGRAM_READY_TIMEOUT_MS` from the environment. Falls back to
42. /// [`DEFAULT_READY_TIMEOUT_MS`] (10 s) if the variable is absent or cannot
43. /// be parsed as a `u64`.
44. fn ready_timeout_ms() -> u64 {
45.     parse_timeout_ms(std::env::var("ENGRAM_READY_TIMEOUT_MS").ok().as_deref())
46. }
47. 
48. // ── Health check ─────────────────────────────────────────────────────────────
49. 
50. /// Check whether a daemon is healthy at `endpoint`.
51. ///
52. /// Sends an `_health` JSON-RPC request with a short timeout. Returns `true`
53. /// if the response contains `"status": "ready"`, `false` on any error or
54. /// unexpected payload.
55. #[instrument(fields(endpoint = %endpoint))]
56. pub async fn check_health(endpoint: &str) -> bool {
57.     let request = IpcRequest {
58.         jsonrpc: "2.0".to_owned(),
59.         id: Some(Value::Number(serde_json::Number::from(0))),
60.         method: "_health".to_owned(),
61.         params: None,
62.     };
63. 
64.     match crate::shim::ipc_client::send_request(endpoint, &request, Duration::from_millis(500))
65.         .await
66.     {
67.         Ok(response) => {
68.             let is_ready = response
69.                 .result
70.                 .as_ref()
71.                 .and_then(|v| v.get("status"))
72.                 .and_then(|s| s.as_str())
73.                 == Some("ready");
74.             debug!(ready = is_ready, "health check returned");
75.             is_ready
76.         }
77.         Err(e) => {
78.             debug!(error = %e, "health check failed");
79.             false
80.         }
81.     }
82. }
83. 
84. // ── Daemon lifecycle ──────────────────────────────────────────────────────────
85. 
86. /// Ensure the daemon is running for `workspace`.
87. ///
88. /// Steps:
89. /// 1. Compute the IPC endpoint for the workspace.
90. /// 2. Perform a health check — if the daemon is already ready, return `Ok(())`.
91. /// 3. Spawn a new daemon process (detached).
92. /// 4. Poll `check_health` with exponential backoff until the daemon is ready
93. ///    or the time budget is exhausted.
94. ///
95. /// # Errors
96. ///
97. /// Returns [`EngramError::Daemon`] if:
98. /// - The daemon binary cannot be located or spawned.
99. /// - The daemon does not become healthy within the configured timeout ms.
100. #[instrument(fields(workspace = %workspace.display()))]
101. pub async fn ensure_daemon_running(workspace: &Path) -> Result<(), EngramError> {
102.     let endpoint = ipc_endpoint(workspace)?;
103. 
104.     if check_health(&endpoint).await {
105.         info!("daemon already running and healthy");
106.         return Ok(());
107.     }
108. 
109.     spawn_daemon(workspace)?;
110. 
111.     poll_until_ready(&endpoint).await
112. }
113. 
114. /// Spawn the daemon as a detached child process for the given workspace.
115. fn spawn_daemon(workspace: &Path) -> Result<(), EngramError> {
116.     let workspace_str = workspace.to_str().ok_or_else(|| {
117.         EngramError::Daemon(DaemonError::SpawnFailed {
118.             reason: "workspace path contains non-UTF-8 characters".to_owned(),
119.         })
120.     })?;
121. 
122.     let current_exe = std::env::current_exe().map_err(|e| {
123.         EngramError::Daemon(DaemonError::SpawnFailed {
124.             reason: format!("cannot locate current executable: {e}"),
125.         })
126.     })?;
127. 
128.     info!(
129.         exe = %current_exe.display(),
130.         workspace = %workspace_str,
131.         "spawning daemon process"
132.     );
133. 
134.     // Spawn detached: all stdio handles closed, no process group membership.
135.     tokio::process::Command::new(&current_exe)
136.         .args(["daemon", "--workspace", workspace_str])
137.         .stdin(std::process::Stdio::null())
138.         .stdout(std::process::Stdio::null())
139.         .stderr(std::process::Stdio::null())
140.         .spawn()
141.         .map_err(|e| {
142.             EngramError::Daemon(DaemonError::SpawnFailed {
143.                 reason: format!("failed to spawn daemon: {e}"),
144.             })
145.         })?;
146. 
147.     Ok(())
148. }
149. 
150. /// Poll the health endpoint with exponential backoff until the daemon is ready.
151. ///
152. /// If the daemon does not become healthy within the budget (wall-clock
153. /// [`ready_timeout_ms()`] ms or [`MAX_BACKOFF_ATTEMPTS`] polls), one final
154. /// check is made to handle the race where a concurrent shim spawned the
155. /// daemon just ahead of us.
156. async fn poll_until_ready(endpoint: &str) -> Result<(), EngramError> {
157.     let timeout_ms = ready_timeout_ms();
158.     let deadline = tokio::time::Instant::now() + Duration::from_millis(timeout_ms);
159.     let mut delay_ms = INITIAL_BACKOFF_MS;
160. 
161.     for attempt in 0..MAX_BACKOFF_ATTEMPTS {
162.         tokio::time::sleep(Duration::from_millis(delay_ms)).await;
163.         delay_ms = (delay_ms * 2).min(MAX_BACKOFF_MS);
164. 
165.         if check_health(endpoint).await {
166.             info!(attempt, "daemon reached ready state");
167.             return Ok(());
168.         }
169. 
170.         if tokio::time::Instant::now() >= deadline {
171.             debug!(attempt, "ready-wait deadline exceeded");
172.             break;
173.         }
174.     }
175. 
176.     // Final check: a concurrent shim may have raced and won the spawn.
177.     if check_health(endpoint).await {
178.         info!("daemon ready (concurrent shim won the spawn race)");
179.         return Ok(());
180.     }
181. 
182.     Err(EngramError::Daemon(DaemonError::NotReady { timeout_ms }))
183. }
