1. //! IPC client: connects to the daemon via `interprocess` `LocalSocketStream`.
2. //!
3. //! Sends a newline-delimited JSON-RPC request and reads the response with
4. //! a configurable timeout. Used exclusively by the shim transport.
5. 
6. use std::time::Duration;
7. 
8. use interprocess::local_socket::tokio::prelude::*;
9. use interprocess::local_socket::tokio::{RecvHalf, SendHalf};
10. use tokio::io::{AsyncBufReadExt, AsyncReadExt, AsyncWriteExt, BufReader};
11. use tracing::instrument;
12. 
13. use crate::daemon::protocol::{IpcRequest, IpcResponse};
14. use crate::errors::{EngramError, IpcError};
15. 
16. /// Send a single IPC request to the daemon at `endpoint` and return the response.
17. ///
18. /// A fresh connection is opened for each call (stateless per-connection per
19. /// the IPC protocol contract). The entire connect + send + receive cycle is
20. /// wrapped in `timeout`.
21. ///
22. /// # Errors
23. ///
24. /// - [`EngramError::Ipc`] with [`IpcError::Timeout`] if the deadline elapses.
25. /// - [`EngramError::Ipc`] with [`IpcError::ConnectionFailed`] if the
26. ///   socket/pipe cannot be reached.
27. /// - [`EngramError::Ipc`] with [`IpcError::SendFailed`] or
28. ///   [`IpcError::ReceiveFailed`] for framing or serialization errors.
29. #[instrument(skip(request), fields(method = %request.method, endpoint = %endpoint))]
30. pub async fn send_request(
31.     endpoint: &str,
32.     request: &IpcRequest,
33.     timeout: Duration,
34. ) -> Result<IpcResponse, EngramError> {
35.     let timeout_ms = u64::try_from(timeout.as_millis()).unwrap_or(u64::MAX);
36.     tokio::time::timeout(timeout, do_send(endpoint, request))
37.         .await
38.         .map_err(|_| EngramError::Ipc(IpcError::Timeout { timeout_ms }))?
39. }
40. 
41. /// Maximum byte count for a single daemon IPC response (1 MiB).
42. ///
43. /// Enforced via [`tokio::io::AsyncReadExt::take`] to prevent a misbehaving
44. /// daemon from causing unbounded allocation in the shim process.
45. const MAX_RESPONSE_BYTES: u64 = 1024 * 1024;
46. 
47. async fn do_send(endpoint: &str, request: &IpcRequest) -> Result<IpcResponse, EngramError> {
48.     let (recv_half, send_half) = connect(endpoint).await?;
49. 
50.     // Serialize the request to a newline-terminated JSON line.
51.     let mut line = serde_json::to_string(request).map_err(|e| {
52.         EngramError::Ipc(IpcError::SendFailed {
53.             reason: e.to_string(),
54.         })
55.     })?;
56.     line.push('\n');
57. 
58.     let mut send_half = send_half;
59.     send_half.write_all(line.as_bytes()).await.map_err(|e| {
60.         EngramError::Ipc(IpcError::SendFailed {
61.             reason: e.to_string(),
62.         })
63.     })?;
64.     send_half.flush().await.map_err(|e| {
65.         EngramError::Ipc(IpcError::SendFailed {
66.             reason: e.to_string(),
67.         })
68.     })?;
69. 
70.     // Read exactly one response line with a 1 MiB size cap to prevent a
71.     // misbehaving daemon from causing unbounded allocation.
72.     let mut reader = BufReader::new(recv_half.take(MAX_RESPONSE_BYTES));
73.     let mut response_line = String::new();
74.     let n = reader.read_line(&mut response_line).await.map_err(|e| {
75.         EngramError::Ipc(IpcError::ReceiveFailed {
76.             reason: e.to_string(),
77.         })
78.     })?;
79. 
80.     // `read_line` returns `Ok(0)` on EOF — the daemon closed the connection
81.     // without writing a response (possible crash or early exit).
82.     if n == 0 {
83.         return Err(EngramError::Ipc(IpcError::ReceiveFailed {
84.             reason: "daemon closed connection without sending a response (possible crash)"
85.                 .to_owned(),
86.         }));
87.     }
88. 
89.     serde_json::from_str(response_line.trim()).map_err(|e| {
90.         EngramError::Ipc(IpcError::ReceiveFailed {
91.             reason: format!("invalid JSON in daemon response: {e}"),
92.         })
93.     })
94. }
95. 
96. // ── Platform-specific connection helpers ─────────────────────────────────────
97. 
98. #[cfg(unix)]
99. async fn connect(endpoint: &str) -> Result<(RecvHalf, SendHalf), EngramError> {
100.     use interprocess::local_socket::{GenericFilePath, ToFsName};
101. 
102.     let name = endpoint.to_fs_name::<GenericFilePath>().map_err(|e| {
103.         EngramError::Ipc(IpcError::ConnectionFailed {
104.             address: endpoint.to_owned(),
105.             reason: e.to_string(),
106.         })
107.     })?;
108. 
109.     let stream = interprocess::local_socket::tokio::Stream::connect(name)
110.         .await
111.         .map_err(|e| {
112.             EngramError::Ipc(IpcError::ConnectionFailed {
113.                 address: endpoint.to_owned(),
114.                 reason: e.to_string(),
115.             })
116.         })?;
117. 
118.     Ok(stream.split())
119. }
120. 
121. #[cfg(windows)]
122. async fn connect(endpoint: &str) -> Result<(RecvHalf, SendHalf), EngramError> {
123.     use interprocess::local_socket::{GenericNamespaced, ToNsName};
124. 
125.     // `GenericNamespaced` expects the pipe name WITHOUT the `\\.\pipe\` prefix.
126.     let pipe_name = endpoint.strip_prefix(r"\\.\pipe\").unwrap_or(endpoint);
127. 
128.     let name = pipe_name.to_ns_name::<GenericNamespaced>().map_err(|e| {
129.         EngramError::Ipc(IpcError::ConnectionFailed {
130.             address: endpoint.to_owned(),
131.             reason: e.to_string(),
132.         })
133.     })?;
134. 
135.     let stream = interprocess::local_socket::tokio::Stream::connect(name)
136.         .await
137.         .map_err(|e| {
138.             EngramError::Ipc(IpcError::ConnectionFailed {
139.                 address: endpoint.to_owned(),
140.                 reason: e.to_string(),
141.             })
142.         })?;
143. 
144.     Ok(stream.split())
145. }
146. 
147. #[cfg(not(any(unix, windows)))]
148. async fn connect(_endpoint: &str) -> Result<(RecvHalf, SendHalf), EngramError> {
149.     Err(EngramError::Ipc(IpcError::ConnectionFailed {
150.         address: _endpoint.to_owned(),
151.         reason: "unsupported platform for IPC".to_owned(),
152.     }))
153. }
154.

