211.     // IPC connection so that long-running sessions can be traced end-to-end.
212.     let connection_id = Uuid::new_v4().to_string();
213.     debug!(connection_id = %connection_id, "ipc_connection_established");
214. 
215.     let (recv_half, mut send_half) = stream.split();
216.     // Cap reads to MAX_REQUEST_BYTES + 1 bytes before buffering so that an
217.     // adversarial local client cannot force unbounded allocation before the
