219.     // to at most MAX_REQUEST_BYTES + 1 bytes; read_line then returns with
220.     // n == MAX_REQUEST_BYTES + 1 which the Err arm below rejects cleanly.
221.     let mut reader = BufReader::new(recv_half.take((MAX_REQUEST_BYTES + 1) as u64));
222.     let mut line = String::new();
223. 
