1. //! Shim module: lightweight stdio MCP proxy.
2. //!
3. //! The shim is the MCP client entry point. It connects to (or spawns) the
4. //! workspace daemon via IPC, then forwards MCP JSON-RPC from stdin to the
5. //! daemon and returns the response to stdout before exiting.
6. 
7. pub mod ipc_client;
8. pub mod lifecycle;
9. pub mod tools_catalog;
10. pub mod transport;
11. 
12. use std::time::Duration;
13. 
14. use crate::errors::{EngramError, WorkspaceError};
15. 
16. /// Run the shim: connect to or spawn the daemon, then proxy stdio MCP calls.
17. ///
18. /// Resolves the workspace from the `ENGRAM_WORKSPACE` environment variable,
19. /// falling back to the current working directory. Ensures the daemon is
20. /// running before starting the MCP stdio server.
21. ///
22. /// # Errors
23. ///
24. /// Returns [`EngramError`] if the daemon cannot be spawned, the IPC connection
25. /// fails, or the MCP transport encounters a protocol error.
26. pub async fn run() -> Result<(), EngramError> {
