30. /// workspace daemon via IPC. Responses with a `content` array have text
31. /// items extracted; other results are serialised as a single text block.
32. /// All other MCP methods use the default no-op implementations from
33. /// [`ServerHandler`].
34. #[derive(Clone)]
35. pub struct ShimHandler {
36.     /// IPC endpoint address for the daemon serving this workspace.
37.     endpoint: String,
38.     /// Request timeout for IPC calls.
39.     timeout: Duration,
40.     /// Monotonically incrementing request-id counter for JSON-RPC requests.
41.     next_id: Arc<AtomicU64>,
42. }
43. 
44. impl ShimHandler {
45.     /// Create a new `ShimHandler` that proxies requests to `endpoint`.
46.     pub fn new(endpoint: String, timeout: Duration) -> Self {
47.         Self {
48.             endpoint,
49.             timeout,
50.             next_id: Arc::new(AtomicU64::new(1)),
51.         }
52.     }
53. 
54.     fn next_id(&self) -> u64 {
55.         self.next_id.fetch_add(1, Ordering::Relaxed)
56.     }
57. }
58. 
59. impl ServerHandler for ShimHandler {
60.     /// Return this shim's identity information.
61.     fn get_info(&self) -> ServerInfo {
62.         ServerInfo::default().with_server_info(Implementation::new(
63.             "engram-shim",
64.             env!("CARGO_PKG_VERSION"),
65.         ))
66.     }
67. 
68.     /// Forward a tool call to the daemon via IPC and translate the response.
69.     #[instrument(skip(self, _cx), fields(tool = %request.name, endpoint = %self.endpoint))]
70.     fn call_tool(
71.         &self,
72.         request: CallToolRequestParams,
73.         _cx: RequestContext<RoleServer>,
74.     ) -> impl std::future::Future<Output = Result<CallToolResult, ErrorData>> + Send + '_ {
75.         async move {
76.             let id = self.next_id();
77. 
78.             let params: Option<Value> = request
79.                 .arguments
80.                 .as_ref()
81.                 .map(|obj| Value::Object(obj.clone()));
82. 
83.             let ipc_req = IpcRequest {
84.                 jsonrpc: "2.0".to_owned(),
85.                 id: Some(Value::Number(serde_json::Number::from(id))),
86.                 method: request.name.to_string(),
87.                 params,
88.             };
89. 
90.             let response =
91.                 crate::shim::ipc_client::send_request(&self.endpoint, &ipc_req, self.timeout)
92.                     .await
93.                     .map_err(domain_to_mcp)?;
94. 
95.             if let Some(wire_err) = response.error {
96.                 return Err(ErrorData::new(
97.                     rmcp::model::ErrorCode(wire_err.code),
98.                     wire_err.message,
99.                     wire_err.data,
100.                 ));
101.             }
102. 
103.             let result_value = response.result.unwrap_or(Value::Null);
104. 
105.             // If the daemon result has a `content` array, extract text items.
106.             // Otherwise serialise the whole result as a single text block.
107.             let content = if let Some(arr) = result_value.get("content").and_then(Value::as_array) {
108.                 arr.iter()
109.                     .filter_map(|item| item.get("text").and_then(Value::as_str).map(Content::text))
110.                     .collect()
111.             } else {
112.                 vec![Content::text(result_value.to_string())]
113.             };
114. 
115.             Ok(CallToolResult::success(content))
116.         }
117.     }
118. 
119.     /// Return the full static tool catalog.
120.     ///
