122.     /// so that MCP clients receive accurate schema information without requiring
123.     /// a round-trip to the daemon.
124.     async fn list_tools(
125.         &self,
126.         _request: Option<PaginatedRequestParams>,
127.         _cx: RequestContext<RoleServer>,
128.     ) -> Result<ListToolsResult, ErrorData> {
129.         Ok(ListToolsResult {
130.             tools: crate::shim::tools_catalog::all_tools(),
131.             next_cursor: None,
132.             meta: None,
133.         })
134.     }
135. }
136. 
137. // ── Error conversion ──────────────────────────────────────────────────────────
138. 
139. fn domain_to_mcp(err: EngramError) -> ErrorData {
140.     ErrorData::internal_error(err.to_string(), None)
141. }
142. 
143. // ── Server entry point ────────────────────────────────────────────────────────
144. 
145. /// Start the shim MCP server over stdio, forwarding requests to `endpoint`.
146. ///
147. /// Blocks until the MCP transport is closed (i.e., the parent process closes
148. /// stdin) or an unrecoverable error occurs.
149. ///
150. /// # Errors
151. ///
152. /// Returns [`EngramError::Ipc`] if the rmcp server fails to initialise.
153. pub async fn run_shim(endpoint: String, timeout: Duration) -> Result<(), EngramError> {
154.     let handler = ShimHandler::new(endpoint, timeout);
155.     let transport = rmcp::transport::io::stdio();
156. 
157.     let running = rmcp::serve_server(handler, transport).await.map_err(|e| {
158.         EngramError::Ipc(IpcError::ConnectionFailed {
159.             address: "stdio".to_owned(),
160.             reason: e.to_string(),
161.         })
162.     })?;
163. 
164.     // Wait for the MCP session to end (client disconnects or EOF on stdin).
165.     // Propagate errors so the caller can distinguish clean shutdown from failures.
166.     running.waiting().await.map_err(|e| {
167.         EngramError::Ipc(IpcError::ConnectionFailed {
168.             address: "stdio".to_owned(),
169.             reason: format!("MCP session ended with error: {e}"),
170.         })
171.     })?;
172.     Ok(())
173. }
