27. /// MCP `ServerHandler` for the shim.
28. ///
29. /// Forwards every [`call_tool`](ServerHandler::call_tool) request to the
30. /// workspace daemon via IPC. Responses with a `content` array have text
31. /// items extracted; other results are serialised as a single text block.
32. /// All other MCP methods use the default no-op implementations from
33. /// [`ServerHandler`].
34. #[derive(Clone)]
35. pub struct ShimHandler {
36.     /// IPC endpoint address for the daemon serving this workspace.
37.     endpoint: String,
38.     /// Request timeout for IPC calls.
39.     timeout: Duration,
40.     /// Monotonically incrementing request-id counter for JSON-RPC requests.
41.     next_id: Arc<AtomicU64>,
42. }
43. 
44. impl ShimHandler {
45.     /// Create a new `ShimHandler` that proxies requests to `endpoint`.
46.     pub fn new(endpoint: String, timeout: Duration) -> Self {
47.         Self {
48.             endpoint,
49.             timeout,
50.             next_id: Arc::new(AtomicU64::new(1)),
51.         }
52.     }
53. 
54.     fn next_id(&self) -> u64 {
55.         self.next_id.fetch_add(1, Ordering::Relaxed)
56.     }
57. }
