671. /// Truncate text to `max_chars`, breaking at a word boundary when possible.
672. fn truncate_summary(text: &str, max_chars: usize) -> String {
673.     if text.chars().count() <= max_chars {
674.         return text.to_string();
675.     }
676.     // Find the byte position at max_chars character boundary (safe for multi-byte chars).
677.     let byte_end = text
678.         .char_indices()
679.         .nth(max_chars)
680.         .map_or(text.len(), |(i, _)| i);
681.     let truncated = &text[..byte_end];
682.     if let Some(pos) = truncated.rfind(' ') {
683.         format!("{}…", &truncated[..pos])
684.     } else {
685.         format!("{truncated}…")
686.     }
687. }
