710. /// Impact analysis: traverse code dependencies and cross-region concerns edges
711. /// to find all tasks affected by changes to a specific code symbol (FR-129).
712. ///
713. /// 1. Resolve `symbol_name` via exact-name lookup.
714. /// 2. BFS traverse code graph to `depth` hops (clamped by FR-149).
715. /// 3. Collect all visited node IDs (root + neighbors).
716. /// 4. Reverse-lookup `concerns` edges to find linked tasks.
717. /// 5. Optionally filter tasks by `status_filter`.
718. /// 6. Return full source bodies for code nodes (FR-148).
719. ///
720. /// # Errors
721. /// - `WorkspaceError::NotSet` (1003) if workspace not bound.
722. /// - `CodeGraphError::SymbolNotFound` (7004) if symbol not in graph.
723. pub async fn impact_analysis(
724.     state: SharedState,
725.     params: Option<Value>,
726. ) -> Result<Value, EngramError> {
727.     ensure_workspace(&state).await?;
728. 
729.     if state.is_indexing() {
730.         return Err(EngramError::CodeGraph(CodeGraphError::IndexInProgress));
731.     }
732. 
733.     let parsed: ImpactAnalysisParams =
734.         serde_json::from_value(params.unwrap_or_default()).map_err(|e| {
735.             EngramError::System(SystemError::InvalidParams {
736.                 reason: format!("invalid params: {e}"),
737.             })
738.         })?;
739. 
740.     // FR-149: clamp depth to config limits.
741.     let config = state.workspace_config().await.unwrap_or_default();
742.     let effective_depth = parsed.depth.clamp(1, config.code_graph.max_traversal_depth);
743.     let effective_max_nodes = parsed
744.         .max_nodes
745.         .clamp(1, 100)
746.         .min(config.code_graph.max_traversal_nodes);
747. 
748.     let workspace_id = workspace_id(&state).await?;
749.     let db = connect_db(&workspace_id).await?;
750.     let cg_queries = CodeGraphQueries::new(db.clone());
751.     let queries = Queries::new(db);
752. 
753.     // Step 1: Resolve symbol name to code node(s).
754.     let matches = cg_queries.find_symbols_by_name(&parsed.symbol_name).await?;
755.     if matches.is_empty() {
756.         return Err(EngramError::CodeGraph(CodeGraphError::SymbolNotFound {
757.             name: parsed.symbol_name,
758.         }));
759.     }
760. 
761.     let root = &matches[0];
762. 
763.     // Step 2: BFS traverse code graph.
764.     let bfs = cg_queries
765.         .bfs_neighborhood(&root.id, effective_depth, effective_max_nodes)
766.         .await?;
767. 
768.     // Step 3: Collect all visited node IDs (root + neighbors).
769.     let mut all_node_ids: Vec<String> = vec![root.id.clone()];
770.     for neighbor in &bfs.neighbors {
771.         all_node_ids.push(neighbor.id.clone());
772.     }
773.     all_node_ids.dedup();
774. 
775.     // Step 4: Reverse-lookup concerns edges to find linked tasks.
776.     let task_symbol_pairs = cg_queries.find_tasks_for_symbols(&all_node_ids).await?;
777. 
778.     // Deduplicate task IDs and collect dependency paths.
779.     let mut task_map: std::collections::HashMap<String, Vec<String>> =
780.         std::collections::HashMap::new();
781.     for (task_id, symbol_id) in &task_symbol_pairs {
782.         task_map
783.             .entry(task_id.clone())
784.             .or_default()
785.             .push(symbol_id.clone());
786.     }
787. 
