789.     let mut affected_tasks: Vec<Value> = Vec::new();
790.     for (task_id, dependency_path) in &task_map {
791.         let raw_id = task_id.strip_prefix("task:").unwrap_or(task_id);
792.         if let Some(task) = queries.get_task(raw_id).await? {
