             context_count: snapshot.context_count,
             last_flush: snapshot.last_flush,
             stale_files: stale_now,
             connection_count: state.active_connections(),
             code_graph,
         });
     }

     Err(EngramError::Workspace(WorkspaceError::NotSet))
 }

