50. ///
51. /// This is a **semantic schema version**, not the crate version. It MUST only
52. /// be incremented when the on-disk `.engram/` file format changes in a way
53. /// that is incompatible with previous readers. Tying it to `CARGO_PKG_VERSION`
54. /// would invalidate every existing workspace on every release.
55. pub const SCHEMA_VERSION: &str = "2.0";
56. 
57. /// Result of a dehydration (flush) operation.
58. #[derive(Debug, Clone)]
59. pub struct DehydrationResult {
60.     pub files_written: Vec<String>,
61.     pub tasks_written: usize,
62.     pub edges_written: usize,
63.     pub comments_preserved: usize,
64.     pub flush_timestamp: String,
65. }
66. 
67. /// Dehydrate full workspace state from the database into `.engram/` files.
68. ///
69. /// Writes `tasks.md`, `graph.surql`, `.version`, and `.lastflush`.
70. /// Preserves user-added comments in existing `tasks.md` (FR-012).
71. pub async fn dehydrate_workspace(
72.     queries: &Queries,
73.     workspace_path: &Path,
74. ) -> Result<DehydrationResult, EngramError> {
75.     let engram_dir = workspace_path.join(".engram");
76.     tokio::fs::create_dir_all(&engram_dir)
77.         .await
78.         .map_err(|_| flush_err(&engram_dir))?;
79. 
80.     let tasks = queries.all_tasks().await?;
81.     let dep_edges = queries.all_dependency_edges().await?;
82.     let impl_edges = queries.all_implements_edges().await?;
83.     let rel_edges = queries.all_relates_to_edges().await?;
84. 
85.     // Read existing tasks.md for comment preservation (FR-012)
86.     let tasks_path = engram_dir.join("tasks.md");
87.     let old_content = tokio::fs::read_to_string(&tasks_path)
88.         .await
89.         .unwrap_or_default();
90.     let old_blocks = parse_task_blocks(&old_content);
