71. pub async fn dehydrate_workspace(
72.     queries: &Queries,
73.     workspace_path: &Path,
74. ) -> Result<DehydrationResult, EngramError> {
75.     let engram_dir = workspace_path.join(".engram");
76.     tokio::fs::create_dir_all(&engram_dir)
77.         .await
78.         .map_err(|_| flush_err(&engram_dir))?;
