83.     let rel_edges = queries.all_relates_to_edges().await?;
84. 
85.     // Read existing tasks.md for comment preservation (FR-012)
86.     let tasks_path = engram_dir.join("tasks.md");
87.     let old_content = tokio::fs::read_to_string(&tasks_path)
88.         .await
89.         .unwrap_or_default();
90.     let old_blocks = parse_task_blocks(&old_content);
91.     let old_bodies: HashMap<String, String> = old_blocks
92.         .into_iter()
93.         .map(|b| (b.task_id, b.body))
94.         .collect();
95.     let comments_preserved = old_bodies.values().filter(|b| !b.trim().is_empty()).count();
96. 
97.     // Collect labels for each task
98.     let mut task_labels: HashMap<String, Vec<String>> = HashMap::new();
99.     for task in &tasks {
100.         let labels = queries.get_labels_for_task(&task.id).await?;
101.         if !labels.is_empty() {
102.             task_labels.insert(task.id.clone(), labels);
103.         }
104.     }
105. 
106.     // Serialize tasks.md preserving user comments
107.     let tasks_content = serialize_tasks_md(&tasks, &old_bodies, &old_content, &task_labels);
108.     atomic_write(&tasks_path, &tasks_content).await?;
109. 
110.     // Serialize graph.surql
111.     let graph_path = engram_dir.join("graph.surql");
112.     let total_edges = dep_edges.len() + impl_edges.len() + rel_edges.len();
113.     let graph_content = serialize_graph_surql(&dep_edges, &impl_edges, &rel_edges);
114.     atomic_write(&graph_path, &graph_content).await?;
115. 
