124.         let _ = tokio::fs::remove_file(&comments_path).await;
125.     }
126. 
127.     // Write version
128.     let version_path = engram_dir.join(".version");
129.     atomic_write(&version_path, SCHEMA_VERSION).await?;
130. 
131.     // Write lastflush timestamp
132.     let flush_ts = Utc::now().to_rfc3339();
133.     let lastflush_path = engram_dir.join(".lastflush");
134.     atomic_write(&lastflush_path, &flush_ts).await?;
135. 
136.     let mut files_written = vec![
137.         ".engram/tasks.md".to_string(),
138.         ".engram/graph.surql".to_string(),
139.         ".engram/.version".to_string(),
140.         ".engram/.lastflush".to_string(),
141.     ];
142. 
143.     if !all_comments.is_empty() {
144.         files_written.push(".engram/comments.md".to_string());
145.     }
146. 
147.     Ok(DehydrationResult {
148.         files_written,
149.         tasks_written: tasks.len(),
150.         edges_written: total_edges,
151.         comments_preserved,
152.         flush_timestamp: flush_ts,
153.     })
154. }
